-- Esquema SQLite exportado desde database/rescate.sqlite (estado tras migraciones Laravel).
-- Fuente canónica del proyecto: modulos/rescate-animales-silvestres-main/database/migrations/*.php
-- Para crear la BD vacía en la app: configurar RESCATE_DB_* y ejecutar php artisan migrate --database=rescate (o el nombre de conexión que usen).

CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE sqlite_sequence(name,seq);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "people" ("id" integer primary key autoincrement not null, "usuario_id" integer, "nombre" varchar not null, "ci" varchar not null, "telefono" varchar, "es_cuidador" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "foto_path" varchar, "cuidador_center_id" integer, "cuidador_aprobado" tinyint(1), "cuidador_motivo_revision" text, foreign key("usuario_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "species" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "animal_statuses" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "centers" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "direccion" varchar, "latitud" numeric, "longitud" numeric, "contacto" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "rescuers" ("id" integer primary key autoincrement not null, "persona_id" integer not null, "created_at" datetime, "updated_at" datetime, "cv_documentado" varchar, "aprobado" tinyint(1), "motivo_revision" text, "motivo_postulacion" text, foreign key("persona_id") references "people"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "veterinarians" ("id" integer primary key autoincrement not null, "especialidad" varchar, "persona_id" integer not null, "created_at" datetime, "updated_at" datetime, "cv_documentado" varchar, "aprobado" tinyint(1), "motivo_revision" text, "motivo_postulacion" text, foreign key("persona_id") references "people"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "treatment_types" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "medical_evaluations" ("id" integer primary key autoincrement not null, "tratamiento_id" integer not null, "descripcion" text, "fecha" date, "veterinario_id" integer not null, "created_at" datetime, "updated_at" datetime, "imagen_url" varchar, "animal_file_id" integer, "diagnostico" text, "peso" numeric, "temperatura" numeric, "tratamiento_texto" text, "recomendacion" varchar, "apto_traslado" varchar, foreign key("tratamiento_id") references "treatment_types"("id") on delete cascade, foreign key("veterinario_id") references "veterinarians"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "care_types" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "descripcion" text, "created_at" datetime, "updated_at" datetime, "es_alimentacion" tinyint(1) not null default '0');
CREATE TABLE IF NOT EXISTS "cares" ("id" integer primary key autoincrement not null, "hoja_animal_id" integer not null, "tipo_cuidado_id" integer not null, "descripcion" text, "fecha" date, "created_at" datetime, "updated_at" datetime, "imagen_url" varchar, foreign key("hoja_animal_id") references "animal_files"("id") on delete cascade, foreign key("tipo_cuidado_id") references "care_types"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "animals" ("id" integer primary key autoincrement not null, "nombre" varchar, "sexo" varchar not null, "descripcion" text, "created_at" datetime, "updated_at" datetime, "reporte_id" integer, foreign key("reporte_id") references "reports"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "animal_files" ("id" integer primary key autoincrement not null, "especie_id" integer not null, "imagen_url" varchar, "estado_id" integer not null, "liberacion_id" integer, "created_at" datetime, "updated_at" datetime, "animal_id" integer, "centro_id" integer, foreign key("animal_id") references animals("id") on delete cascade on update no action, foreign key("especie_id") references species("id") on delete cascade on update no action, foreign key("estado_id") references animal_statuses("id") on delete cascade on update no action, foreign key("liberacion_id") references releases("id") on delete set null on update no action);
CREATE TABLE IF NOT EXISTS "animal_histories" ("id" integer primary key autoincrement not null, "animal_file_id" integer not null, "changed_at" datetime not null default CURRENT_TIMESTAMP, "estado_anterior" text not null, "estado_nuevo" text not null, "observaciones" text not null, "old_values" text, "new_values" text, foreign key("animal_file_id") references "animal_files"("id") on delete cascade);
CREATE INDEX "animal_file_history_animal_file_id_changed_at_index" on "animal_histories" ("animal_file_id", "changed_at");
CREATE TABLE IF NOT EXISTS "releases" ("id" integer primary key autoincrement not null, "direccion" varchar, "detalle" text, "latitud" numeric, "longitud" numeric, "aprobada" tinyint(1) not null default ('0'), "created_at" datetime, "updated_at" datetime, "animal_file_id" integer, "imagen_url" varchar, foreign key("animal_file_id") references "animal_files"("id") on delete cascade);
CREATE UNIQUE INDEX "releases_animal_file_id_unique" on "releases" ("animal_file_id");
CREATE TABLE IF NOT EXISTS "feeding_types" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "descripcion" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "feeding_frequencies" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "descripcion" text, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "feeding_portions" ("id" integer primary key autoincrement not null, "cantidad" integer not null, "unidad" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "care_feedings" ("id" integer primary key autoincrement not null, "care_id" integer not null, "feeding_type_id" integer not null, "feeding_frequency_id" integer not null, "feeding_portion_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("care_id") references "cares"("id") on delete cascade, foreign key("feeding_type_id") references "feeding_types"("id") on delete cascade, foreign key("feeding_frequency_id") references "feeding_frequencies"("id") on delete cascade, foreign key("feeding_portion_id") references "feeding_portions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "transfers" ("id" integer primary key autoincrement not null, "rescatista_id" integer not null, "centro_id" integer not null, "observaciones" varchar, "created_at" datetime, "updated_at" datetime, "persona_id" integer, "primer_traslado" tinyint(1) not null default '1', "animal_id" integer, "latitud" numeric, "longitud" numeric, "reporte_id" integer, foreign key("persona_id") references people("id") on delete cascade on update no action, foreign key("rescatista_id") references rescuers("id") on delete cascade on update no action, foreign key("centro_id") references centers("id") on delete cascade on update no action, foreign key("animal_id") references "animals"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "animal_conditions" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "severidad" integer not null default '3', "activo" tinyint(1) not null default '1');
CREATE TABLE IF NOT EXISTS "incident_types" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "riesgo" integer not null default '1', "activo" tinyint(1) not null default '1');
CREATE TABLE IF NOT EXISTS "reports" ("id" integer primary key autoincrement not null, "persona_id" integer not null, "aprobado" tinyint(1) not null default ('0'), "imagen_url" varchar, "observaciones" varchar, "created_at" datetime, "updated_at" datetime, "latitud" numeric, "longitud" numeric, "direccion" varchar, "condicion_inicial_id" integer, "tipo_incidente_id" integer, "tamano" varchar, "puede_moverse" tinyint(1), "urgencia" integer, "incendio_id" integer, foreign key("persona_id") references people("id") on delete cascade on update no action, foreign key("condicion_inicial_id") references "animal_conditions"("id"), foreign key("tipo_incidente_id") references "incident_types"("id"));
CREATE TABLE IF NOT EXISTS "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);
CREATE INDEX "personal_access_tokens_tokenable_type_tokenable_id_index" on "personal_access_tokens" ("tokenable_type", "tokenable_id");
CREATE UNIQUE INDEX "personal_access_tokens_token_unique" on "personal_access_tokens" ("token");
CREATE INDEX "personal_access_tokens_expires_at_index" on "personal_access_tokens" ("expires_at");
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null default 'web', "created_at" datetime, "updated_at" datetime);
CREATE UNIQUE INDEX "permissions_name_guard_name_unique" on "permissions" ("name", "guard_name");
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null default 'web', "created_at" datetime, "updated_at" datetime);
CREATE UNIQUE INDEX "roles_name_guard_name_unique" on "roles" ("name", "guard_name");
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("permission_id", "model_id", "model_type"));
CREATE INDEX "model_has_permissions_model_id_model_type_index" on "model_has_permissions" ("model_id", "model_type");
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("role_id", "model_id", "model_type"));
CREATE INDEX "model_has_roles_model_id_model_type_index" on "model_has_roles" ("model_id", "model_type");
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "contact_messages" ("id" integer primary key autoincrement not null, "user_id" integer not null, "motivo" varchar not null, "mensaje" text not null, "leido" tinyint(1) not null default '0', "leido_at" datetime, "leido_por" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "user_tracking" ("id" integer primary key autoincrement not null, "user_id" integer, "performed_by" integer, "action_type" varchar not null, "action_description" varchar not null, "related_model_type" varchar, "related_model_id" integer, "valores_antiguos" text, "valores_nuevos" text, "metadata" text, "realizado_en" datetime not null default CURRENT_TIMESTAMP, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);
CREATE INDEX "user_tracking_user_id_realizado_en_index" on "user_tracking" ("user_id", "realizado_en");
CREATE INDEX "user_tracking_performed_by_realizado_en_index" on "user_tracking" ("performed_by", "realizado_en");
CREATE INDEX "user_tracking_action_type_index" on "user_tracking" ("action_type");
CREATE INDEX "user_tracking_related_model_type_related_model_id_index" on "user_tracking" ("related_model_type", "related_model_id");
CREATE INDEX "user_tracking_realizado_en_index" on "user_tracking" ("realizado_en");
CREATE UNIQUE INDEX "people_ci_unique" on "people" ("ci");
